def _upsert_agent(agent_model, seed):
    agent = (
        agent_model.objects.filter(id=seed["id"]).first()
        or agent_model.objects.filter(name=seed["name"], organization__isnull=True).first()
    )

    if agent is None:
        return agent_model.objects.create(
            id=uuid.UUID(seed["id"]),
            organization=None,
            name=seed["name"],
            description=seed["description"],
            available_options=seed["available_options"],
            default_env=seed["default_env"],
            supports_multi_chat=seed["supports_multi_chat"],
        )

    agent.organization = None
    agent.name = seed["name"]
    agent.description = seed["description"]
    agent.available_options = seed["available_options"]
    agent.default_env = seed["default_env"]
    agent.supports_multi_chat = seed["supports_multi_chat"]
    agent.save()
    return agent


def _upsert_agent_command(agent_command_model, agent, command_seed):
    command = (
        agent_command_model.objects.filter(id=command_seed["id"]).first()
        or agent_command_model.objects.filter(
            agent=agent,
            phase=command_seed["phase"],
            order=command_seed["order"],
        ).first()
    )

    if command is None:
        agent_command_model.objects.create(
            id=uuid.UUID(command_seed["id"]),
            agent=agent,
            phase=command_seed["phase"],
            args=command_seed["args"],
            workdir=command_seed["workdir"],
            env=command_seed["env"],
            description=command_seed["description"],
            order=command_seed["order"],
        )
        return

    command.agent = agent
    command.phase = command_seed["phase"]
    command.args = command_seed["args"]
    command.workdir = command_seed["workdir"]
    command.env = command_seed["env"]
    command.description = command_seed["description"]
    command.order = command_seed["order"]
    command.save()


