def seed_global_agent_and_image_definitions(apps, schema_editor):
    agent_model = apps.get_model("runners", "AgentDefinition")
    agent_command_model = apps.get_model("runners", "AgentCommand")
    relation_model = apps.get_model("runners", "AgentDefinitionCredentialRelation")
    image_definition_model = apps.get_model("runners", "ImageDefinition")
    organization_model = apps.get_model("organizations", "Organization")
    agent_activation_model = apps.get_model("runners", "OrgAgentDefinitionActivation")
    credential_service_model = apps.get_model("credentials", "CredentialService")
    seeded_agents = []

    for agent_seed in AGENT_SEEDS:
        agent = _upsert_agent(agent_model, agent_seed)
        seeded_agents.append(agent)

        required_services = list(
            credential_service_model.objects.filter(
                slug__in=agent_seed["required_credential_service_slugs"]
            )
        )
        agent.required_credential_services.set(required_services)

        for relation_seed in agent_seed["credential_relations"]:
            credential_service = credential_service_model.objects.filter(
                slug=relation_seed["credential_service_slug"]
            ).first()
            if credential_service is None:
                continue

            relation = (
                relation_model.objects.filter(id=relation_seed["id"]).first()
                or relation_model.objects.filter(
                    agent_definition=agent,
                    credential_service=credential_service,
                ).first()
            )
            if relation is None:
                relation_model.objects.create(
                    id=uuid.UUID(relation_seed["id"]),
                    agent_definition=agent,
                    credential_service=credential_service,
                    default_env=relation_seed["default_env"],
                )
            else:
                relation.agent_definition = agent
                relation.credential_service = credential_service
                relation.default_env = relation_seed["default_env"]
                relation.save()

        for command_seed in agent_seed["commands"]:
            _upsert_agent_command(agent_command_model, agent, command_seed)

    for image_seed in IMAGE_SEEDS:
        _upsert_image_definition(image_definition_model, image_seed)

    organizations = list(organization_model.objects.all())
    agent_activation_model.objects.bulk_create(
        [
            agent_activation_model(organization=org, agent_definition=agent)
            for org in organizations
            for agent in seeded_agents
        ],
        ignore_conflicts=True,
    )


def unseed_global_agent_and_image_definitions(apps, schema_editor):
    agent_model = apps.get_model("runners", "AgentDefinition")
    image_definition_model = apps.get_model("runners", "ImageDefinition")

    agent_model.objects.filter(id__in=[uuid.UUID(seed["id"]) for seed in AGENT_SEEDS]).delete()
    image_definition_model.objects.filter(
        id__in=[uuid.UUID(seed["id"]) for seed in IMAGE_SEEDS]
    ).delete()


